+              deleted: false,
+              profile: { email: "person@example.com", display_name: "Person" },
+            },
+          ],
+        }),
+      },
+    };
+
+    const res = await resolveSlackUserAllowlist({
+      token: "xoxb-test",
+      entries: ["person@example.com"],
+      client: client as never,
+    });
