+      resolved: true,
+      id: "U2",
+      name: "Person",
+      email: "person@example.com",
+      isBot: false,
+    });
+  });
+
+  it("keeps unresolved users", async () => {
+    const client = {
+      users: {
+        list: vi.fn().mockResolvedValue({ members: [] }),
+      },
+    };
